const regStart = new Date('2026-02-10')
const regEnd   = new Date('2026-05-11')

const profileIds = users.map(() => randomUUID())

const profileRows = users.map((u, i) => {
  const id   = profileIds[i]
  const bio  = bios[i]
  const date = randDate(regStart, regEnd)
  return `${id},"${u.name}",${u.email},"${bio}",NULL,${u.is_admin},${date}`
})

const profilesCsv = ['id,name,email,bio,avatar,is_admin,registered_at', ...profileRows].join('\n')

