// assign proof types
function makeProof() {
  const r = Math.random()
  if (r < 0.35) return { proof_type: 'none', proof_value: 'NULL' }
  if (r < 0.65) return { proof_type: 'link', proof_value: `https://example.com/proof/${Math.random().toString(36).slice(2, 10)}` }
  return { proof_type: 'photo', proof_value: `https://example.com/photos/${Math.random().toString(36).slice(2, 10)}.jpg` }
}

const achievementRows = []
const achievementIds = []

let seq = 1
for (const [category, items] of Object.entries(achievementsByCategory)) {
  for (const item of items) {
    const id = randomUUID()
    achievementIds.push(id)
    const userId = profileIds[randInt(0, 49)]
    const year = randInt(2022, 2025)
    const { proof_type, proof_value } = makeProof()
    const createdAt = randDate(achStart, achEnd)
    const pv = proof_value === 'NULL' ? 'NULL' : `"${proof_value}"`
    achievementRows.push(`${id},${userId},${category},"${item.title}","${item.description}",${year},${proof_type},${pv},verified,${createdAt}`)
    seq++
  }
}

const achievementsCsv = ['id,user_id,category,title,description,year,proof_type,proof_value,status,created_at', ...achievementRows].join('\n')

console.log(`Generated ${achievementIds.length} achievements`)

// ─── likes ─────────────────────────────────────────────────────────────────

const likesStart = new Date('2025-11-11')
const likesEnd   = new Date('2026-05-11')

const likeSet = new Set()
const likeRows = []

// ensure each achievement gets at least 1 like
for (const achId of achievementIds) {
  const userId = profileIds[randInt(0, 49)]
  const key = `${achId}:${userId}`
  if (!likeSet.has(key)) {
    likeSet.add(key)
    likeRows.push(`${randomUUID()},${achId},${userId},${randDate(likesStart, likesEnd)}`)
  }
}

// fill up to ~380 total
while (likeRows.length < 380) {
  const achId  = achievementIds[randInt(0, achievementIds.length - 1)]
  const userId = profileIds[randInt(0, 49)]
  const key = `${achId}:${userId}`
  if (!likeSet.has(key)) {
    likeSet.add(key)
    likeRows.push(`${randomUUID()},${achId},${userId},${randDate(likesStart, likesEnd)}`)
  }
}

const likesCsv = ['id,achievement_id,user_id,created_at', ...likeRows].join('\n')

console.log(`Generated ${likeRows.length} likes`)

// ─── write files ───────────────────────────────────────────────────────────

writeFileSync('seed/profiles.csv', profilesCsv, 'utf8')
writeFileSync('seed/achievements.csv', achievementsCsv, 'utf8')
writeFileSync('seed/likes.csv', likesCsv, 'utf8')

console.log('Done! Files written to seed/')
